#!/bin/bash
# Pytest testing workflow
set -e

pip install pytest pytest-cov pytest-xdist

# Create a sample test file if none exists
mkdir -p tests
cat > tests/test_example.py << 'PYEOF'
import pytest

def add(a, b):
    return a + b

class TestAdd:
    def test_integers(self):
        assert add(1, 2) == 3

    def test_strings(self):
        assert add("hello ", "world") == "hello world"

    @pytest.mark.parametrize("a,b,expected", [
        (0, 0, 0),
        (-1, 1, 0),
        (100, 200, 300),
    ])
    def test_parametrized(self, a, b, expected):
        assert add(a, b) == expected

@pytest.fixture
def sample_data():
    return {"users": ["alice", "bob"], "count": 2}

def test_with_fixture(sample_data):
    assert len(sample_data["users"]) == sample_data["count"]
PYEOF

pytest tests/ -v --tb=short
pytest tests/ --cov=tests --cov-report=term-missing

echo "All tests passed with coverage report."
